            greet: 'emote',
            acknowledge: 'emote',
            yes: 'emote',
            deny: 'emote',
            no: 'emote',
            alert: 'talk',
            hurt: 'hit',
            damage: 'hit',
            flinch: 'hit',
            die: 'death',
            pickup: 'pickup',
            idle_reset: 'idle',
            locomotion_start: 'walk',
            locomotion_stop: 'idle'
