                _envRunHistoryState.lastRequestedExecutionId = '';
                _envRunHistoryState.lastRequestTs = 0;
                _envRunHistoryState.refreshedTs = 0;
                _envRunHistoryState.error = '';
                _envHealthState.workflowId = '';
                _envHealthState.pendingStatus = false;
